('610/1335/3','EDK3-008','Electrical Scientific Principles and Technologies for Work in Dwellings',7,'Understand AC electrical properties.','7.3','Identify the relationship between kW, kVAr, kVA and power factor.'),
('610/1335/3','EDK3-008','Electrical Scientific Principles and Technologies for Work in Dwellings',7,'Understand AC electrical properties.','7.4','Explain how electrical loads affect current demand.'),
('610/1335/3','EDK3-008','Electrical Scientific Principles and Technologies for Work in Dwellings',8,'Understand the operating principles of electrical components.','8.1','Explain the operating principles of electrical components.'),
('610/1335/3','EDK3-008','Electrical Scientific Principles and Technologies for Work in Dwellings',9,'Understand the principles and applications of electrical lighting systems.','9.1','Apply the basic principles of illumination.'),
('610/1335/3','EDK3-008','Electrical Scientific Principles and Technologies for Work in Dwellings',9,'Understand the principles and applications of electrical lighting systems.','9.2','Explain the operating principles, types, limitations and applications of luminaires and lamp types.'),
('610/1335/3','EDK3-008','Electrical Scientific Principles and Technologies for Work in Dwellings',9,'Understand the principles and applications of electrical lighting systems.','9.3','Explain the key technical aspects of lighting specifications.'),
('610/1335/3','EDK3-008','Electrical Scientific Principles and Technologies for Work in Dwellings',10,'Understand the principles and applications of heating systems.','10.1','Explain the basic principles of electrical space heating and electrical water heating.'),
('610/1335/3','EDK3-008','Electrical Scientific Principles and Technologies for Work in Dwellings',10,'Understand the principles and applications of heating systems.','10.2','Explain the operating principles, types, limitations and applications of electrical space and water heating appliances and components.'),
('610/1335/3','EDK3-008','Electrical Scientific Principles and Technologies for Work in Dwellings',10,'Understand the principles and applications of heating systems.','10.3','Apply heat loss calculations: a) R = T/K; b) Heat Loss Q=UA (T1-T2).');
INSERT INTO qualification_requirements (qualification_code, unit_code, unit_title, lo_number, lo_text, ac_code, ac_text) VALUES
('610/1335/3','EDP3-001','Apply Health, Safety and Environmental Considerations in Dwellings',1,'Be able to apply relevant health and safety legislation in the workplace','1.1','Identify which workplace health and safety procedures are relevant to working in domestic dwelling environments and comply with their duties and obligations as defined by current legislation and organisational procedures'),
('610/1335/3','EDP3-001','Apply Health, Safety and Environmental Considerations in Dwellings',1,'Be able to apply relevant health and safety legislation in the workplace','1.2','Produce a risk assessment and method statement in accordance with organisational procedures for a given work activity'),
('610/1335/3','EDP3-001','Apply Health, Safety and Environmental Considerations in Dwellings',1,'Be able to apply relevant health and safety legislation in the workplace','1.3','Work within the requirements of: a) risk assessments; b) method statements; c) safe systems of work'),
('610/1335/3','EDP3-001','Apply Health, Safety and Environmental Considerations in Dwellings',2,'Be able to assess the work environment for hazards and identify remedial actions in accordance with health and safety legislation','2.1','Identify unsafe situations and conditions and take remedial actions'),
('610/1335/3','EDP3-001','Apply Health, Safety and Environmental Considerations in Dwellings',2,'Be able to assess the work environment for hazards and identify remedial actions in accordance with health and safety legislation','2.2','Assess the work environment and revise work practices accordingly to take into account hazards which could cause harm, including the handling of potentially hazardous: a) materials; b) tools; c) equipment'),
('610/1335/3','EDP3-001','Apply Health, Safety and Environmental Considerations in Dwellings',2,'Be able to assess the work environment for hazards and identify remedial actions in accordance with health and safety legislation','2.3','Identify any hazards which may present a high risk and report their presence to relevant persons who have overall responsibility for health and safety in the workplace'),
('610/1335/3','EDP3-001','Apply Health, Safety and Environmental Considerations in Dwellings',2,'Be able to assess the work environment for hazards and identify remedial actions in accordance with health and safety legislation','2.4','Apply measures to control health and safety hazards'),
('610/1335/3','EDP3-001','Apply Health, Safety and Environmental Considerations in Dwellings',2,'Be able to assess the work environment for hazards and identify remedial actions in accordance with health and safety legislation','2.5','Select and use correct personal protective equipment'),
('610/1335/3','EDP3-001','Apply Health, Safety and Environmental Considerations in Dwellings',3,'Be able to apply methods and procedures to ensure work on site is in accordance with health and safety legislation','3.1','Ensure that the health and safety of themselves and others is not endangered through personal conduct and behaviour within the workplace'),
('610/1335/3','EDP3-001','Apply Health, Safety and Environmental Considerations in Dwellings',3,'Be able to apply methods and procedures to ensure work on site is in accordance with health and safety legislation','3.2','Apply procedures to ensure the safe use, maintenance and storage of tools, plant and equipment as stipulated in: a) workplace policies (company and site); b) supplier information; c) manufacturer''s instructions'),
('610/1335/3','EDP3-001','Apply Health, Safety and Environmental Considerations in Dwellings',3,'Be able to apply methods and procedures to ensure work on site is in accordance with health and safety legislation','3.3','Comply with information, warning, mandatory instruction and prohibition notices'),
('610/1335/3','EDP3-001','Apply Health, Safety and Environmental Considerations in Dwellings',3,'Be able to apply methods and procedures to ensure work on site is in accordance with health and safety legislation','3.4','Apply procedures to ensure the safety of the work location through the correct use of guards barriers and notices'),
('610/1335/3','EDP3-001','Apply Health, Safety and Environmental Considerations in Dwellings',3,'Be able to apply methods and procedures to ensure work on site is in accordance with health and safety legislation','3.5','Use access equipment correctly: a) ladder; b) tower scaffold or MEWP; c) stepladder; d) platform'),
('610/1335/3','EDP3-001','Apply Health, Safety and Environmental Considerations in Dwellings',4,'Be able to work in accordance with environmental legislation for electrical services','4.1','Use appropriate procedures for the safe handling, storage and disposal of hazardous materials and products');
INSERT INTO qualification_requirements (qualification_code, unit_code, unit_title, lo_number, lo_text, ac_code, ac_text) VALUES
('610/1335/3','EDP3-003','Plan and Oversee Electrical Work Activities in Dwellings',1,'Be able to provide relevant people with technical and functional information for work on electrical systems and equipment','1.1','Liaise with relevant people to evaluate the information they require to ensure that systems, equipment or components can be operated safely and effectively'),
('610/1335/3','EDP3-003','Plan and Oversee Electrical Work Activities in Dwellings',1,'Be able to provide relevant people with technical and functional information for work on electrical systems and equipment','1.2','Identify appropriate technical and functional information that is required for the work activity'),
('610/1335/3','EDP3-003','Plan and Oversee Electrical Work Activities in Dwellings',1,'Be able to provide relevant people with technical and functional information for work on electrical systems and equipment','1.3','Provide information in a timely, courteous, suitable and professional manner in accordance with organisational procedures and engineering standards'),
('610/1335/3','EDP3-003','Plan and Oversee Electrical Work Activities in Dwellings',2,'Be able to co-ordinate liaison with other relevant persons during work activities','2.1','Select effective methods to co-ordinate with other workers/contractors, including steps to resolve issues or delays'),
('610/1335/3','EDP3-003','Plan and Oversee Electrical Work Activities in Dwellings',2,'Be able to co-ordinate liaison with other relevant persons during work activities','2.2','Apply communication techniques that are clear, accurate and appropriate to the situation'),
('610/1335/3','EDP3-003','Plan and Oversee Electrical Work Activities in Dwellings',2,'Be able to co-ordinate liaison with other relevant persons during work activities','2.3','Apply principles of customer service'),
('610/1335/3','EDP3-003','Plan and Oversee Electrical Work Activities in Dwellings',3,'Be able to organise and oversee work activities and operations in dwellings','3.1','Organise operatives by allocating duties and responsibilities to make the best use of their competence and skill'),
('610/1335/3','EDP3-003','Plan and Oversee Electrical Work Activities in Dwellings',3,'Be able to organise and oversee work activities and operations in dwellings','3.2','Monitor the work of operatives to ensure it is in accordance with: industry working practices; programme of work; health and safety requirements; cost effectiveness; environmental considerations'),
('610/1335/3','EDP3-003','Plan and Oversee Electrical Work Activities in Dwellings',4,'Be able to organise a programme for working on single-phase electrical systems and equipment','4.1','Produce a simple programme of work from the work specification, including requirements for the following: estimate of the amount of time required for completion of the work; liaison with other trades where necessary'),
('610/1335/3','EDP3-003','Plan and Oversee Electrical Work Activities in Dwellings',4,'Be able to organise a programme for working on single-phase electrical systems and equipment','4.2','Communicate with others clearly and concisely'),
('610/1335/3','EDP3-003','Plan and Oversee Electrical Work Activities in Dwellings',4,'Be able to organise a programme for working on single-phase electrical systems and equipment','4.3','Liaise with other relevant parties to resolve issues or delays'),
('610/1335/3','EDP3-003','Plan and Oversee Electrical Work Activities in Dwellings',5,'Be able to organise the resource requirements for work on electrical systems and equipment in dwellings','5.1','Organise provision of resources to include: materials; fixings; plant; labour; tools'),
('610/1335/3','EDP3-003','Plan and Oversee Electrical Work Activities in Dwellings',5,'Be able to organise the resource requirements for work on electrical systems and equipment in dwellings','5.2','Confirm that materials available are: the right type; fit for purpose; in the correct quantity; suitable for work to be completed cost efficiently'),
('610/1335/3','EDP3-003','Plan and Oversee Electrical Work Activities in Dwellings',5,'Be able to organise the resource requirements for work on electrical systems and equipment in dwellings','5.3','Ensure that resources are undamaged at the point of delivery'),
('610/1335/3','EDP3-003','Plan and Oversee Electrical Work Activities in Dwellings',5,'Be able to organise the resource requirements for work on electrical systems and equipment in dwellings','5.4','Implement measures which ensure the safe and effective storage of materials, tools and equipment in the work location');
INSERT INTO qualification_requirements (qualification_code, unit_code, unit_title, lo_number, lo_text, ac_code, ac_text) VALUES
('610/1335/3','EDP3-004','Apply Design and Installation Practices including Termination and Connection of Conductors in Dwellings',1,'Prepare to install wiring systems, enclosures and associated equipment in dwellings','1.1','Apply appropriate procedures to include: a) adopting appropriate PPE; b) following a safe system of work (e.g. working in accordance with a risk assessment and method statement); c) selecting appropriate tools/equipment for the installation work'),
('610/1335/3','EDP3-004','Apply Design and Installation Practices including Termination and Connection of Conductors in Dwellings',1,'Prepare to install wiring systems, enclosures and associated equipment in dwellings','1.2','Prepare to install wiring systems, enclosures and associated equipment, to include: a) report any pre-work damage/defects to existing equipment or building features, to the relevant person (such as: customer/client, site/line manager); b) confirm site readiness for installation work to begin; c) confirm authorisation for the installation work to start'),
('610/1335/3','EDP3-004','Apply Design and Installation Practices including Termination and Connection of Conductors in Dwellings',1,'Prepare to install wiring systems, enclosures and associated equipment in dwellings','1.3','Use documentation to confirm that materials and equipment is of the correct quantity and is free from damage'),
('610/1335/3','EDP3-004','Apply Design and Installation Practices including Termination and Connection of Conductors in Dwellings',1,'Prepare to install wiring systems, enclosures and associated equipment in dwellings','1.4','Ensure the planned locations for the wiring system and associated equipment are compatible with other building services (e.g. Gas, water or other electrical services)'),
('610/1335/3','EDP3-004','Apply Design and Installation Practices including Termination and Connection of Conductors in Dwellings',1,'Prepare to install wiring systems, enclosures and associated equipment in dwellings','1.5','Check the planned locations for the wiring system in terms of: a) cosmetic appearance; b) external influences'),
('610/1335/3','EDP3-004','Apply Design and Installation Practices including Termination and Connection of Conductors in Dwellings',2,'Interpret appropriate information for the installation of wiring systems, enclosures and associated equipment','2.1','Use sources of information to enable the installation of wiring systems, enclosures and associated equipment to be carried out: Assess two of the following: a) specifications; b) work schedules/programmes; c) manufacturer instructions; d) layout drawings; e) other appropriate source of information (e.g. BS 7671, other plans or diagrams, ''approved documents'', building regulations)'),
('610/1335/3','EDP3-004','Apply Design and Installation Practices including Termination and Connection of Conductors in Dwellings',3,'Install wiring systems, and equipment in accordance with current relevant statutory and non-statutory regulations','3.1','Use measuring and marking out techniques which are appropriate to the wiring system, wiring enclosure and/or associated equipment that is being installed'),
('610/1335/3','EDP3-004','Apply Design and Installation Practices including Termination and Connection of Conductors in Dwellings',3,'Install wiring systems, and equipment in accordance with current relevant statutory and non-statutory regulations','3.2','Install cables in accordance with BS 7671, the installation specification and programme of work: Assess four from: a) single core (singles); b) multicore insulated; c) PVC - PVC flat profile cable; d) DC cabling; e) SWA cable; f) data including PoE; g) fire resistant cabling (not including MICC)'),
('610/1335/3','EDP3-004','Apply Design and Installation Practices including Termination and Connection of Conductors in Dwellings',3,'Install wiring systems, and equipment in accordance with current relevant statutory and non-statutory regulations','3.3','Install the following in accordance with the wiring regulations, the installation specification and agreed planned programme of work: Assess three from: a) PVC conduit; b) PVC trunking; c) cable basket; d) cable tray'),
('610/1335/3','EDP3-004','Apply Design and Installation Practices including Termination and Connection of Conductors in Dwellings',3,'Install wiring systems, and equipment in accordance with current relevant statutory and non-statutory regulations','3.4','Install the following types of electrical equipment and accessories, in accordance with, BS 7671, the installation specification, manufacturers'' instructions and the programme of work: Assess all the following: a) distribution boards/consumer units; b) socket outlets; c) luminaires; d) isolators/switches; e) overcurrent protective devices AND - Assess four from the following: a) electric vehicle charging point; b) fire detection components; c) data socket outlets; d) WI FI Router; e) smart Camera and or Smart Doorbell; f) smart Lighting Control (not individual smart lamp); g) smart Heating Controls including hard wired connections; h) other appropriate equipment within a dwelling (e.g. heating system components, control equipment)'),
('610/1335/3','EDP3-004','Apply Design and Installation Practices including Termination and Connection of Conductors in Dwellings',3,'Install wiring systems, and equipment in accordance with current relevant statutory and non-statutory regulations','3.5','Dispose of waste materials in accordance with site procedures and statutory requirements'),
('610/1335/3','EDP3-004','Apply Design and Installation Practices including Termination and Connection of Conductors in Dwellings',4,'Confirm the quality of the completed work','4.1','Make good all parts of the building following installation work'),
('610/1335/3','EDP3-004','Apply Design and Installation Practices including Termination and Connection of Conductors in Dwellings',4,'Confirm the quality of the completed work','4.2','Ensure the installed wiring system/s and enclosure/s meet specified requirements including that they: a) are the correct type and fit for purpose; b) are installed in accordance with BS 7671; c) meet the installation specification/other relevant plans/instructions; d) are installed in accordance with any relevant manufacturer instructions'),
('610/1335/3','EDP3-004','Apply Design and Installation Practices including Termination and Connection of Conductors in Dwellings',5,'Prepare to terminate and connect cables and conductors used in dwellings','5.1','Apply appropriate procedures to include: a) selecting appropriate tools/equipment to enable termination and connection; b) adopting appropriate PPE; c) following a safe system of work (e.g. risk assessment, method statement, permit to work procedure).'),
('610/1335/3','EDP3-004','Apply Design and Installation Practices including Termination and Connection of Conductors in Dwellings',5,'Prepare to terminate and connect cables and conductors used in dwellings','5.2','Ensure it is safe to complete termination and connection in terms of: a) checking for presence of supply/carrying out safe isolation; b) mechanical soundness of the electrical equipment to be connected to; c) checking for unsafe situations.'),
('610/1335/3','EDP3-004','Apply Design and Installation Practices including Termination and Connection of Conductors in Dwellings',6,'Terminate and connect conductors and cables used in dwellings','6.1','Terminate and connect cables and conductors in accordance with manufacturer''s instructions, BS 7671, and any relevant drawing or specification: Assess four from the following: a) single core (singles); b) multicore insulated; c) PVC - PVC flat profile cable; d) DC cabling; e) SWA cable; f) data including PoE; g) fire resistant cabling (not including MICC)'),
('610/1335/3','EDP3-004','Apply Design and Installation Practices including Termination and Connection of Conductors in Dwellings',6,'Terminate and connect conductors and cables used in dwellings','6.2','Connect to electrical equipment in accordance with manufacturer''s instructions, BS 7671, and any relevant drawing or specification: Assess five from the following: a) isolators /switches; b) socket outlets; c) distribution-boards / consumer control units; d) luminaires; e) overcurrent protective devices; f) earthing terminals; g) data socket outlets or data connections; h) wired fire detection/alarm components; i) other appropriate equipment within a dwelling (such as: heating system components)'),
('610/1335/3','EDP3-004','Apply Design and Installation Practices including Termination and Connection of Conductors in Dwellings',6,'Terminate and connect conductors and cables used in dwellings','6.3','Terminate and connect conductors, using appropriate methods: Assess two from the following: a) screwing; b) crimping; c) non-screw compression; d) insulation displacement'),
('610/1335/3','EDP3-004','Apply Design and Installation Practices including Termination and Connection of Conductors in Dwellings',6,'Terminate and connect conductors and cables used in dwellings','6.4','Ensure that terminations and connections are electrically and mechanically sound (inspecting and testing terminations)'),
('610/1335/3','EDP3-004','Apply Design and Installation Practices including Termination and Connection of Conductors in Dwellings',6,'Terminate and connect conductors and cables used in dwellings','6.5','Ensure cables have appropriate identification in accordance with BS 7671');
INSERT INTO qualification_requirements (qualification_code, unit_code, unit_title, lo_number, lo_text, ac_code, ac_text) VALUES
('610/1335/3','EDP3-006','Inspect, Test, Report and Commission Electrical Systems in Dwellings',1,'Be able to confirm safety of the system and equipment prior to completion of inspection, testing and commissioning of single-phase systems in accordance with statutory and non-statutory regulations','1.1','Carry out safe isolation procedures in accordance with regulatory requirements for electrical installations'),
('610/1335/3','EDP3-006','Inspect, Test, Report and Commission Electrical Systems in Dwellings',1,'Be able to confirm safety of the system and equipment prior to completion of inspection, testing and commissioning of single-phase systems in accordance with statutory and non-statutory regulations','1.2','Check for diverted neutral currents on PME installations'),
('610/1335/3','EDP3-006','Inspect, Test, Report and Commission Electrical Systems in Dwellings',1,'Be able to confirm safety of the system and equipment prior to completion of inspection, testing and commissioning of single-phase systems in accordance with statutory and non-statutory regulations','1.3','Ensure the health and safety of themselves and others within the work location during inspection, testing and commissioning'),
('610/1335/3','EDP3-006','Inspect, Test, Report and Commission Electrical Systems in Dwellings',1,'Be able to confirm safety of the system and equipment prior to completion of inspection, testing and commissioning of single-phase systems in accordance with statutory and non-statutory regulations','1.4','Check the safety of electrical systems prior to the commencement of inspection, testing and commissioning'),
('610/1335/3','EDP3-006','Inspect, Test, Report and Commission Electrical Systems in Dwellings',2,'Be able to inspect single-phase electrical systems and equipment','2.1','Assess whether the safe system of work is appropriate to the work activity'),
('610/1335/3','EDP3-006','Inspect, Test, Report and Commission Electrical Systems in Dwellings',2,'Be able to inspect single-phase electrical systems and equipment','2.2','Carry out a visual inspection in accordance with the requirements of the installation specification, BS 7671 and IET Guidance Note 3'),
('610/1335/3','EDP3-006','Inspect, Test, Report and Commission Electrical Systems in Dwellings',2,'Be able to inspect single-phase electrical systems and equipment','2.3','Complete necessary inspections documentation in accordance with the BS 7671 and IET Guidance Note 3 making technical decisions'),
('610/1335/3','EDP3-006','Inspect, Test, Report and Commission Electrical Systems in Dwellings',3,'Be able to test and commission single-phase electrical systems and equipment','3.1','Select the correct test instruments and their accessories for tests'),
('610/1335/3','EDP3-006','Inspect, Test, Report and Commission Electrical Systems in Dwellings',3,'Be able to test and commission single-phase electrical systems and equipment','3.2','Carry out tests in accordance with the installation specification and BS 7671 and manufacturer''s instructions: Tests include: continuity; insulation resistance; polarity; earth fault loop impedance/earth electrode; prospective fault current; RCD operation; functional testing'),
('610/1335/3','EDP3-006','Inspect, Test, Report and Commission Electrical Systems in Dwellings',3,'Be able to test and commission single-phase electrical systems and equipment','3.3','Verify test results reporting all findings to relevant persons, as appropriate: representatives of other services/colleagues; customers/clients'),
('610/1335/3','EDP3-006','Inspect, Test, Report and Commission Electrical Systems in Dwellings',3,'Be able to test and commission single-phase electrical systems and equipment','3.4','Complete in accordance with BS 7671 and IET Guidance Note 3: Electrical installation certificates and associated documents; Minor electrical installation works certificates'),
('610/1335/3','EDP3-006','Inspect, Test, Report and Commission Electrical Systems in Dwellings',3,'Be able to test and commission single-phase electrical systems and equipment','3.5','Complete the handover of electrical systems and equipment to relevant persons including the provision of accurate and completed documentation regarding the completed inspection, testing, commissioning and customer satisfaction'),
('610/1335/3','EDP3-006','Inspect, Test, Report and Commission Electrical Systems in Dwellings',3,'Be able to test and commission single-phase electrical systems and equipment','3.6','Demonstrate to the customer/client that the operation of the circuits, equipment and components are in accordance with the installation specification and customer/client requirements'),
('610/1335/3','EDP3-006','Inspect, Test, Report and Commission Electrical Systems in Dwellings',4,'Be able to inspect, test and report on the condition of an existing electrical installation','4.1','Collate the information that is needed to enable sampling to be set'),
('610/1335/3','EDP3-006','Inspect, Test, Report and Commission Electrical Systems in Dwellings',4,'Be able to inspect, test and report on the condition of an existing electrical installation','4.2','Agree and set samples with client and other stakeholders based on the quality of information and systems and maintenance'),
('610/1335/3','EDP3-006','Inspect, Test, Report and Commission Electrical Systems in Dwellings',4,'Be able to inspect, test and report on the condition of an existing electrical installation','4.3','Agree extents and limitations with client and/or other stakeholders'),
('610/1335/3','EDP3-006','Inspect, Test, Report and Commission Electrical Systems in Dwellings',4,'Be able to inspect, test and report on the condition of an existing electrical installation','4.4','Carry out an inspection of an installation in accordance with the agreed sample, extents and limitations'),
('610/1335/3','EDP3-006','Inspect, Test, Report and Commission Electrical Systems in Dwellings',4,'Be able to inspect, test and report on the condition of an existing electrical installation','4.5','Carry out the necessary tests of an installation in accordance with the agreed sample, extents and limitations'),
('610/1335/3','EDP3-006','Inspect, Test, Report and Commission Electrical Systems in Dwellings',4,'Be able to inspect, test and report on the condition of an existing electrical installation','4.6','Report on the condition of an installation using the correct report codes and documentation'),
('610/1335/3','EDP3-006','Inspect, Test, Report and Commission Electrical Systems in Dwellings',4,'Be able to inspect, test and report on the condition of an existing electrical installation','4.7','Communicate findings of report to necessary stakeholders following completion of the report');
INSERT INTO qualification_requirements (qualification_code, unit_code, unit_title, lo_number, lo_text, ac_code, ac_text) VALUES
('610/1335/3','EDP3-007','Apply Fault Diagnosis and Rectification in Dwellings',1,'Prepare to carry out fault diagnosis in dwellings','1.1','Check it is safe to carry out fault diagnosis'),
('610/1335/3','EDP3-007','Apply Fault Diagnosis and Rectification in Dwellings',1,'Prepare to carry out fault diagnosis in dwellings','1.2','Inform the relevant personnel of the fault diagnosis work (such as personnel on the premises, users of electrical equipment)'),
('610/1335/3','EDP3-007','Apply Fault Diagnosis and Rectification in Dwellings',1,'Prepare to carry out fault diagnosis in dwellings','1.3','Carry out the safe isolation procedure'),
('610/1335/3','EDP3-007','Apply Fault Diagnosis and Rectification in Dwellings',1,'Prepare to carry out fault diagnosis in dwellings','1.4','Apply appropriate methods to ensure the safety of themselves and others when diagnosing and correcting electrical faults'),
('610/1335/3','EDP3-007','Apply Fault Diagnosis and Rectification in Dwellings',2,'Carry out fault diagnosis in dwellings','2.1','Communicate effectively with relevant personnel (e.g. Customer) to ascertain the nature of the fault'),
('610/1335/3','EDP3-007','Apply Fault Diagnosis and Rectification in Dwellings',2,'Carry out fault diagnosis in dwellings','2.2','Interpret documents which relate to the electrical systems and equipment being worked upon'),
('610/1335/3','EDP3-007','Apply Fault Diagnosis and Rectification in Dwellings',2,'Carry out fault diagnosis in dwellings','2.3','Communicate potential disruption that may be a consequence of fault diagnosis and correction work to relevant people, to include: a) other workers/colleagues; b) customers/clients'),
('610/1335/3','EDP3-007','Apply Fault Diagnosis and Rectification in Dwellings',2,'Carry out fault diagnosis in dwellings','2.4','Carry out relevant inspections of electrical equipment analysing findings'),
('610/1335/3','EDP3-007','Apply Fault Diagnosis and Rectification in Dwellings',2,'Carry out fault diagnosis in dwellings','2.5','Confirm test instruments are fit for purpose, functioning correctly and are correctly calibrated'),
('610/1335/3','EDP3-007','Apply Fault Diagnosis and Rectification in Dwellings',2,'Carry out fault diagnosis in dwellings','2.6','Perform suitable diagnostic tests, based on engineering decision, to identify electrical faults: Assess three from the following: a) loss of supply; b) overload; c) short-circuit; d) earth fault; e) high resistance joints/loose terminations; f) component, accessory or equipment faults; g) open circuit'),
('610/1335/3','EDP3-007','Apply Fault Diagnosis and Rectification in Dwellings',2,'Carry out fault diagnosis in dwellings','2.7','Use appropriate methods for locating faults including: a) using a logical approach; b) using safe working practices; c) interpretation of test readings'),
('610/1335/3','EDP3-007','Apply Fault Diagnosis and Rectification in Dwellings',2,'Carry out fault diagnosis in dwellings','2.8','Use appropriate instruments correctly to carry out fault diagnosis: Assess three of the following: a) voltage indicator; b) low resistance ohm meter; c) insulation resistance tester; d) ELZ and PFC tester; e) RCD tester; f) ammeter; g) other appropriate instrument'),
('610/1335/3','EDP3-007','Apply Fault Diagnosis and Rectification in Dwellings',3,'Carry out fault rectification in dwellings','3.1','Assess the appropriate repairs, removals and replacements and their implications with relevant people: Assess one of the following: a) other workers/colleagues; b) customers/clients'),
('610/1335/3','EDP3-007','Apply Fault Diagnosis and Rectification in Dwellings',3,'Carry out fault rectification in dwellings','3.2','Perform fault correction procedures correctly and safely using appropriate tools, equipment and material'),
('610/1335/3','EDP3-007','Apply Fault Diagnosis and Rectification in Dwellings',3,'Carry out fault rectification in dwellings','3.3','Verify that replacement components and associated equipment maintain: a) ease of access to enable future maintenance; b) compliance with relevant regulations; c) compliance with manufacturer’s instructions/ organisational procedures'),
('610/1335/3','EDP3-007','Apply Fault Diagnosis and Rectification in Dwellings',3,'Carry out fault rectification in dwellings','3.4','Apply procedures to ensure electrical equipment and components are left safe, in accordance with industry regulations, if the fault cannot be corrected immediately based on technical assessment'),
('610/1335/3','EDP3-007','Apply Fault Diagnosis and Rectification in Dwellings',3,'Carry out fault rectification in dwellings','3.5','Perform an inspection and testing procedure to confirm that circuits/equipment/components are functioning correctly after completion of fault correction work'),
('610/1335/3','EDP3-007','Apply Fault Diagnosis and Rectification in Dwellings',3,'Carry out fault rectification in dwellings','3.6','Record test results and other information regarding the fault correction work clearly and accurately and report it to relevant people: Assess one of the following: a) other workers/colleagues; b) customers/clients; c) representatives of other services');
